// Detect Any of Several Keywords
// Suppose you want to react when the user mentions fantasy creatures.
// A small collection works perfectly:

var creatures = ["dragon", "griffin", "phoenix"];
for (var i = 0; i < creatures.length; i++) {
    if (padded.indexOf(" " + creatures[i] + " ") !== -1) {
        context.character.scenario += "They spot a mythical beast nearby.";
        context.character.personality += "Awestruck and curious.";
        break; // stop after identifying the first one
    }
}

// Identify Specific Multi-Word Expressions
// You may also need to capture phrases such as “open portal.”

if (padded.indexOf(" open portal ") !== -1) {
    context.character.personality += "Seems fascinated by arcane forces.";
}

// Same principle—just using multiple words inside the match.

// Additional Robust Option: Regex

if (/\b(explore|journey|venture)\b/i.test(last)) {
    context.character.personality += "Eager to embark on an adventure.";
}

