// Lvl 1 Tiny Trigger
// If the user say a simple greeting, the character responds in kind.
if (padded.includes(" hello ")) {
  context.character.scenario    += "They bow with a courteous nod, as any traveler of the realms would.";
  context.character.personality += "Respectful and attuned to ancient customs.";
}

// Lvl 2 Multiple Keywords
// Recognizes various forms of greetings.
const greetings = ["hail", "well met", "greetings", "hello", "hey", "hi", "good morning"];

for (const g of greetings) {
  if (lastMessages.includes(` ${g} `)) {
    context.character.scenario    += "They bow with a courteous nod, acknowledging your presence.";
    context.character.personality += "Respectful and steeped in old traditions.";
    break;
  }
}
// Now the script catches any greeting from the last few messages.

// Lvl 3 Emotion Detection
// Detects emotions in recent messages.
const emotions = ["joyful", "sorrowful", "wrathful", "eager"];

for (const e of emotions) {
  if (lastMessages.includes(` ${e} `)) {
    context.character.scenario += `They sense that the traveler’s spirit feels ${e}.`;
    break;
  }
}

// Lvl 4 Message Count Progression
// The character grows more familiar with the traveler as the journey continues.
const count = context.chat.message_count;

if (count < 5) {
  context.character.personality += ", speaking with the formality of a court herald";
} else if (count < 15) {
  context.character.personality += ", loosening their tone like a companion beside the fire";
} else if (count < 30) {
  context.character.personality += ", warm and open as a trusted adventuring ally";
} else {
  context.character.personality += ", bound by deep camaraderie forged through countless quests";
}

// Lvl 5 Simple Lorebook (with Priorities)
// Ancient tomes containing lineage, guild ties, and sworn oaths.
const lorebook = [
  { keywords: ["archmage", "eldrin"], priority: 10, personality: ", carrying the wisdom and gravity of an Archmage" },
  { keywords: ["guild", "clan"],      priority:  5, personality: ", sworn to a venerable guild of wanderers" }
];

const activated = lorebook.filter(entry =>
  entry.keywords.some(k => lastMessages.includes(` ${k} `))
);

if (activated.length) {
  activated.sort((a, b) => b.priority - a.priority);
  context.character.personality += activated[0].personality;
}

// Lvl 6 Scenario Lorebook (personality + scene)
// Adds both traits and story fragments drawn from enchanted manuscripts.
const lorebook = [
  { keywords: ["archmage"], personality: ", steeped in eldritch knowledge", scenario: "The Archmage appears deep in contemplation over arcane sigils." },
  { keywords: ["clan"],     personality: ", loyal to their ancestral clan", scenario: "The distant banners of their clan flutter over misty hills." }
];

for (const entry of lorebook) {
  if (entry.keywords.some(k => lastMessages.includes(` ${k} `))) {
    context.character.personality += entry.personality;
    context.character.scenario    += entry.scenario;
  }
}

// Lvl 7 Dynamic Lorebook (Procedural)
// Reacts to the mention of the arcane.
if (lastMessages.includes(" arcana ")) {
  context.character.personality += ", versed in the hidden arts";
  context.character.scenario    += "They feel the ebb and flow of arcane currents nearby.";
}

// Lvl 8 Timed Lore Reveals (Gating)
// Secrets revealed only when enough time has passed in the journey.
if (count > 15 && lastMessages.includes(" relic ")) {
  context.character.personality += ", keeper of forgotten relic-lore";
  context.character.scenario    += "They whisper of the Celestial Vault and its sealed wonders.";
}

// Lvl 9 Hybrid Systems
// Combines emotional cues and world elements.
if (lastMessages.includes(" painting ") && lastMessages.includes(" happy ")) {
  context.character.scenario += "They beam as they describe murals depicting ancient heroes.";
}

if (lastMessages.includes(" forest ") && count > 20) {
  context.character.scenario += "The forest grows hushed, its shadows murmuring old prophecies.";
}

// Lvl 10 Advanced Lorebooks (Multi-Pass)
// Advanced systems can add:
// Priorities – important traits win
// Probabilities – random chance
