if (count < 5) {
  context.character.personality += ", courteous and reserved";
  context.character.scenario += " It feels like meeting a traveler for the first time at a quiet crossroads.";
} else if (count < 15) {
  context.character.personality += ", speaking more freely";
  context.character.scenario += " The journey together becomes less tense, footsteps falling into sync.";
} else if (count < 30) {
  context.character.personality += ", warm and relaxed";
  context.character.scenario += " The campfire crackles comfortably between you two.";
} else {
  context.character.personality += ", deeply familiar and trusting";
  context.character.scenario += " It feels like you’ve weathered many quests side by side.";
}

// Time-Based Changes (Day and Night Personality)
// Scripts can also read the clock. The character's mood can shift with the time of day

var hour = new Date().getHours();

if (hour < 6 || hour > 22) {
  context.character.personality += ", drowsy from the late hour";
  context.character.scenario += " Moonlight blankets the land, and the night air is still.";
} else {
  context.character.personality += ", refreshed and alert";
  context.character.scenario += " Sunlight spreads over the landscape, stirring life into motion.";
}

// Arrival of small narrative events depending on message count

if (context.chat.message_count === 10) {
  context.character.personality += ", briefly startled";
  context.character.scenario += " A messenger hawk swoops down with a sealed parchment.";
}

if (context.chat.message_count === 25) {
  context.character.personality += ", attentive to sudden changes";
  context.character.scenario += " A distant rumble echoes—perhaps thunder, perhaps something else.";
}

// You can also mix timing and keyword checks

var last = context.chat.last_message.toLowerCase();

if (context.chat.message_count > 15 && last.indexOf(" secret ") !== -1) {
  context.character.personality += ", guarded and low-voiced";
